from sys import stdin

def input():
    return stdin.readline()

def tide(k, t):
    t = t % (2 * k)
    if t <= k:
        return t
    else:
        return 2 * k - t

def solve():
    n, k, l = map(int, input().split())
    dd = list(map(int, input().split()))
    if max(dd) > l:
        print("No")
        return

    memo = {}

    def can_reach(pos, time):
        if pos == n:
            return True
        key = (pos, time % (2 * k))
        if key in memo:
            return memo[key]
        # Option 1: stay in current position
        new_time = time + 1
        if dd[pos] + tide(k, new_time) <= l:
            if can_reach(pos, new_time):
                memo[key] = True
                return True
        # Option 2: move to next position
        if pos + 1 <= n:
            new_time = time + 1
            if pos + 1 < n:
                if dd[pos + 1] + tide(k, new_time) <= l:
                    if can_reach(pos + 1, new_time):
                        memo[key] = True
                        return True
            else:
                memo[key] = True
                return True
        memo[key] = False
        return False

    for start_time in range(2 * k):
        if can_reach(0, start_time):
            print("Yes")
            return
    print("No")

def main():
    t = int(input())
    for _ in range(t):
        solve()

if __name__ == "__main__":
    main()
